719     APInt U = (CR.Upper - 1).ugt(Upper - 1) ? CR.Upper : Upper;
720 
721     if (L.isZero() && U.isZero())
722       return getFull();
723 
724     return ConstantRange(std::move(L), std::move(U));
725   }
726 
727   if (!CR.isUpperWrapped()) {
728     // ------U   L-----  and  ------U   L----- : this
729     //   L--U                            L--U  : CR
