2053 static ConstantRange getUnsignedCountTrailingZerosRange(const APInt &Lower,
2054                                                         const APInt &Upper) {
2055   assert(!ConstantRange(Lower, Upper).isWrappedSet() &&
2056          "Unexpected wrapped set.");
