2068   // Otherwise, the maximum is BitWidth - LCPLength - 1 ({LCP, 100...}).
2069   return ConstantRange(
2070       APInt::getZero(BitWidth),
2071       APInt(BitWidth,
2072             std::max(BitWidth - LCPLength - 1, Lower.countr_zero()) + 1));
